rules.formula:
var lot=(F('Work Order :: Production Run Lot #')||'').trim();
if(/^n[\/\\]?a$/i.test(lot)) return 'warn';
return lot.length>3;

var start = F('Work Order :: Actual Start');
var finish = F('Work Order :: Actual Finish');
var dur = F('Work Order :: Duration');
if (!start || !finish) return false;
var d = hours(dur);
var a = hoursBetween(start, finish);
if (d == null || d === 0 || a == null) return false;
return d <= a;

var wt = F('Work Order :: Work Type');
if (!oneOf(wt, ['DM','DMPDM','DMPM','FDM','RBLD','SAFDM','TRBL','SDDM'])) return true;
if (!notEmpty(F('Work Order :: Asset'))) return true;
return rowCount('m69f3c12d') > 0;

var text=[F('Work Order :: Description'),F('Work Order :: Reason for Maintenance'),F('Work Order :: As Found Condition'),F('Work Order :: Work Performed')].join(' ');
var self=F('Work Order :: Work Order');
var found=matches(text,'\\b\\d{6}\\b').filter(function(f){return f!==self;});
if(found.length===0) return 'na';
var vals=col('Related Work Orders','Work Order');
return found.every(function(f){return vals.some(function(v){return (v||'').indexOf(f)>=0;});});

var laborRows = rowCount('Labor');
if (laborRows === 0) return false;
var dur = hours(F('Work Order :: Duration'));
var totalHrs = col('Labor', 'Regular Hours').reduce(function(s, v) {
  var h = hours(v);
  return s + (h || 0);
}, 0);
if (dur != null && totalHrs > dur) return false;

var desc = F('Work Order :: Description') || '';
var hasTrainingKeyword = /\btraining\b/i.test(desc) || /\bTT\b/.test(desc);
if (hasTrainingKeyword) {
  var laborTypes = col('Labor', 'Labor Type');
  if (!laborTypes.length) return 'warn';
  var trainingCount = laborTypes.filter(function(v) {
    return (v || '').toUpperCase() === 'TRAINING';
  }).length;
  if (trainingCount < laborTypes.length) return 'warn';
}
return true;

var lot = (F('Work Order :: Production Run Lot #') || '').trim();
if (lot.length < 4) return true;
var grp1 = (F('Approvers :: Approval Group 1') || '').trim();
var grp2 = (F('Approvers :: Approval Group 2') || '').trim();
var grp3 = (F('Approvers :: Approval Group 3') || '').trim();
var filled = grp1 || grp2 || grp3;
if (!filled) return false;
var knownGroups = ['AVWP-PRD-B1', 'AVWP-PRD-B1-C1', 'AVWP-PRD-B-PACK'];
var isKnown = knownGroups.indexOf(filled) !== -1;
if (!isKnown) return 'na';
return true;

var desc = (F('Work Order :: Description') || '').trim();
var reason = (F('Work Order :: Reason for Maintenance') || '').trim();
var asFound = (F('Work Order :: As Found Condition') || '').trim();
var workDone = (F('Work Order :: Work Performed') || '').trim();

if (!desc || !reason || !asFound || !workDone) return false;

var naPattern = /^(n\/?a|not\s+applicable|none|n\.a\.?)$/i;
var fields = [desc, reason, asFound, workDone];

var hasNA = fields.some(function(v) { return naPattern.test(v); });
if (hasNA) return 'warn';

var hasShort = fields.some(function(v) { return v.length < 30; });
if (hasShort) return 'warn';

var seen = {};
var hasDup = fields.filter(function(v) { return v.length > 0; }).some(function(v) {
    var k = v.toLowerCase();
    if (seen[k]) return true;
    seen[k] = 1;
    return false;
});
if (hasDup) return 'warn';

return true;

var wt = (F('Work Order :: Work Type') || '').trim();
var pri = (F('Work Order :: Priority') || '').trim();
var wg = (F('Work Order :: Work Group') || '').trim();
var lead = (F('Work Order :: Lead') || '').trim();
var owner = (F('Work Order :: Owner') || '').trim();
if (!wt || !pri || !wg || !lead || !owner) return false;
return true;

rowDetailFields.collectCondition:
var desc = F('Work Order :: Description') || '';
var descLow = desc.toLowerCase();
return descLow.indexOf('training') >= 0
    || /\bTT\b/.test(desc);

scans.condition:
var lot=(F('Work Order :: Production Run Lot #')||'').trim();
if(/^n\/?a$/i.test(lot)) return false;
return lot.length>3;

vars.formula:
var fields = [
    F('Work Order :: Asset Description'),
    F('Work Order :: Description'),
    F('Work Order :: Reason for Maintenance'),
    F('Work Order :: As Found Condition'),
    F('Work Order :: Work Performed')
];

var core1 = /\b(core\s*1|c1|pfs2?|pfc|allotrope)\b/i;
var core2 = /\b(core\s*2|c2)\b/i;
var core3 = /\b(core\s*3|c3)\b/i;

for (var i = 0; i < fields.length; i++) {
    var val = (fields[i] || '').trim();
    if (!val) continue;
    if (core1.test(val)) return 'Core 1';
    if (core2.test(val)) return 'Core 2';
    if (core3.test(val)) return 'Core 3';
}
return '';
